import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.ActorMaterializer
import scala.concurrent.ExecutionContextExecutor

object WebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem()
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  val route =
    path("fetch") {
      post {
        entity(as[String]) { url =>
          val request = HttpRequest(uri = url)
          onComplete(Http().singleRequest(request)) {
            case Success(response) =>
              response.entity.dataBytes.runFold(ByteString(""))(_ ++ _).map(data => HttpResponse(status = response.status, entity = HttpEntity(data)))
            case Failure(exception) =>
              HttpResponse(status = StatusCodes.InternalServerError, entity = HttpEntity(ContentTypes.`application/json`, s"""{"error": "${exception.getMessage}"}"""))
          }
        }
      }
    }

  val bindingFuture = Http().newServerAt("localhost", 8080).bind(route)

  println(s"Server online at http://localhost:8080/\nPress RETURN to stop...")
  scala.io.StdIn.readLine()
  bindingFuture.flatMap(_.unbind()).onComplete(_ => system.terminate())
}